class Solution:
    def strobogrammaticInRange(self, low: str, high: str) -> int:
        def is_strobogrammatic(num):
            """Check if a number is strobogrammatic."""
            mapping = {'0': '0', '1': '1', '6': '9', '8': '8', '9': '6'}
            rotated = []

            for digit in num:
                if digit not in mapping:
                    return False
                rotated.append(mapping[digit])

            return ''.join(rotated[::-1]) == num

        def generate_strobogrammatic(n):
            """Generate strobogrammatic numbers of length n."""
            if n == 0: return [""]
            if n == 1: return ["0", "1", "8"]

            smaller = generate_strobogrammatic(n - 2)
            result = []
            for mid in smaller:
                for pair in ["00", "11", "69", "88", "96"]:
                    if n != len(low) and pair == "00":
                        continue  # Avoid leading zero
                    result.append(pair[0] + mid + pair[1])
            return result

        def count_strobogrammatic_in_range(low, high):
            """Count the strobogrammatic numbers between low and high."""
            count = 0
            for length in range(len(low), len(high) + 1):
                for num in generate_strobogrammatic(length):
                    if low <= num <= high:
                        count += 1
            return count

        return count_strobogrammatic_in_range(low, high)
```

