class Solution:
    def longestIdealString(self, s: str, k: int) -> int:
        # Initialize a dp array representing the longest ideal string ending with each letter
        dp = [0] * 26  # There are 26 lowercase English letters
        offset = ord('a')  # To convert between characters and their index (0 for 'a', 1 for 'b', etc.)

        for char in s:
            index = ord(char) - offset  # Get the index of the current character
            # Calculate the max length for this character considering the k constraint
            max_length = 0
            for i in range(max(index - k, 0), min(index + k, 25) + 1):
                max_length = max(max_length, dp[i])
            dp[index] = max_length + 1  # Update dp for the current character

        # The result is the maximum value within the dp array
        return max(dp)
```

